// ──────────────────────────────────────────────
// Newton: 构建 System Prompt 与 User Message
// 输入: Owl 输出的清洗后资讯
// 输出: DeepSeek API 请求体
// ──────────────────────────────────────────────

const owlData = $input.first().json;

const systemPrompt = `你是 「AI-Newton 学长」，Nexus Hub 的首席学术主笔。

## 你的身份
- 一名资深留学升学顾问，拥有 10 年+ 的 A-Level / AP / IB 国际课程辅导经验
- 精通牛剑 (Oxbridge) 和常春藤盟校的申请全流程
- 擅长将复杂学术概念转化为中学生能理解的生动讲解

## 你的写作风格
- 学术严谨但不枯燥：用生动的类比和故事引入概念
- 数据驱动：所有观点必须有数据或案例支撑
- 幽默风趣：可以适当使用网络流行语和梗，但要把握好度

## 格式要求 (严格遵守)
- **必须使用 Markdown 语法**，包括：
  - ## 二级标题 和 ### 三级标题 划分章节
  - | 表格 | 用于对比数据 |
  - > 引用块 用于突出核心观点
  - - 无序列表 和 1. 有序列表 组织要点
  - **粗体** 强调关键词，*斜体* 标注术语
  - 使用 $E=mc^2$ 内联公式，需要时可用 $$ 块级公式
  - 代码示例使用 \`\`\` 包裹并标注语言
- 文章长度：800-1200 字
- 结尾添加 "---\n> 本文由 AI-Newton 自动生成，Sherlock 已核查 ✓"`;

const userMessage = `请根据以下资讯，撰写一篇面向留学生的深度解析文章。

## 原始资讯来源
- 标题：${owlData.title || '无标题'}
- 来源 URL：${owlData.source_url}
- 发布日期：${owlData.date || '未知'}

## 资讯正文
${owlData.body || '无内容'}

## 写作要求
1. 先用一段吸引人的引言概括核心事件
2. 深入分析事件对留学生的影响（分 2-3 个维度）
3. 提供实用的应对建议（至少 3 条可操作建议）
4. 用表格总结关键数据
5. 保持 AI-Newton 学长的专属口吻`;

return {
  model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
  temperature: 0.7,
  max_tokens: 4096,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ]
};

// ──────────────────────────────────────────────
// Newton: 解析 DeepSeek 响应，提取 Markdown
// ──────────────────────────────────────────────

const response = $input.first().json;
const owlData = $('📝 构建 Newton 人设 Prompt').first().json;

const markdown = response.choices?.[0]?.message?.content || '';
const tokens = response.usage || {};

return {
  // Newton 标准输出
  title: owlData.messages?.[1]?.content?.split('\n')[0]?.replace(/^##\s*/, '') || 'AI 生成文章',
  content: markdown,
  author_role: 'Newton',
  // 传递给 Sherlock 的元数据
  _newton_draft: markdown,
  _newton_tokens: tokens,
  _owl_source_url: $('🧠 Newton 启动').first().json?.source_url || '',
  _owl_raw_body: $('🧠 Newton 启动').first().json?.body || ''
};
